// Input: item.json["Select Webinar"] (the Base64-URL string from the Calendar link)
// Output: item.json.apiEventId (for Update Event) and item.json.calendarId

return items.map(item => {
  const raw = String(item.json["Select Webinar"] || '').trim();
  if (!raw) throw new Error('Missing Select Webinar input');

  // Convert base64url → base64
  const b64 = raw.replace(/-/g, '+').replace(/_/g, '/');
  let decoded;
  try {
    decoded = Buffer.from(b64, 'base64').toString('utf8');
  } catch (err) {
    throw new Error('Failed to decode eventId: ' + err.message);
  }

  // decoded looks like: "<eventId> <calendarId>"
  const [apiEventId, calendarId] = decoded.split(' ');
  if (!apiEventId || !calendarId) {
    throw new Error('Could not split decoded value: ' + decoded);
  }

  item.json.apiEventId = apiEventId;   // <- use this for Event ID
  item.json.calendarId = calendarId;   // <- use this for Calendar field
  return item;
});
